<script setup lang="ts">import { reactive, ref } from 'vue';import { useRouter } from 'vue-router';import { ApiError } from '@ct/shared';import { ElMessage } from 'element-plus';import { auth } from '../api';import AppShell from '../components/AppShell.vue';import { useAuthStore } from '../stores/auth';const store=useAuthStore();const router=useRouter();const loading=ref(false);const error=ref('');const form=reactive({old_password:'',new_password:'',confirm_password:''});async function submit(){error.value='';if(form.new_password.length<8){error.value='新密码至少 8 位';return}if(form.new_password!==form.confirm_password){error.value='两次输入的新密码不一致';return}loading.value=true;try{await auth.changePassword(form.old_password,form.new_password);store.user=null;ElMessage.success('密码已修改，请重新登录');await router.replace('/login')}catch(e){error.value=e instanceof ApiError&&e.status===401?'旧密码错误':'密码修改失败，请稍后重试'}finally{loading.value=false}}</script>
<template><AppShell title="设置"><section class="panel settings-card"><h2>账户信息</h2><el-descriptions :column="2" border><el-descriptions-item label="用户名">{{store.user?.username}}</el-descriptions-item><el-descriptions-item label="角色">{{store.user?.role}}</el-descriptions-item></el-descriptions></section><section class="panel settings-card"><h2>修改密码</h2><el-form :model="form" label-width="110px" @submit.prevent="submit"><el-form-item label="旧密码"><el-input v-model="form.old_password" type="password" show-password autocomplete="current-password"/></el-form-item><el-form-item label="新密码"><el-input v-model="form.new_password" type="password" show-password autocomplete="new-password"/></el-form-item><el-form-item label="确认新密码"><el-input v-model="form.confirm_password" type="password" show-password autocomplete="new-password" @keyup.enter="submit"/></el-form-item><el-alert v-if="error" :title="error" type="error" :closable="false" show-icon/><el-form-item><el-button type="primary" native-type="submit" :loading="loading">修改密码</el-button></el-form-item></el-form></section></AppShell></template>
